import json, sys, re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Bash":
        return 0

    cmd = inp.get("command", "")

    # Only check git commit commands with -m flag
    if not ("git commit" in cmd and "-m" in cmd):
        return 0

    # Extract commit message from HEREDOC or -m flag
    commit_msg = None

    # Try HEREDOC first
    heredoc_match = re.search(r"cat\s+<<['\"]?EOF['\"]?\s*\n(.+?)\n\s*EOF", cmd, re.DOTALL)
    if heredoc_match:
        commit_msg = heredoc_match.group(1).strip()
    else:
        # Try simple -m flag
        msg_match = re.search(r'-m\s+["\'](.+?)["\']', cmd, re.DOTALL)
        if msg_match:
            commit_msg = msg_match.group(1)

    if not commit_msg:
        return 0

    lines = [line.strip() for line in commit_msg.strip().split('\n')]
    # Remove empty leading lines
    while lines and not lines[0]:
        lines.pop(0)

    if not lines:
        return 0

    subject = lines[0]

    # Rule 1: subject line length
    if len(subject) > 72:
        sys.stderr.write(
            f"Subject line too long ({len(subject)} chars, max 72). "
            f"Team convention: short imperative lines like 'Refactor auth: extract token validation'.\n"
        )
        return 2

    # Rule 2: subject should not contain periods (indicates multiple sentences or paragraph-style)
    if '. ' in subject or subject.endswith('.'):
        sys.stderr.write(
            f"Subject line contains periods (paragraph-style). "
            f"Team convention: short imperative lines like 'Refactor auth: extract token validation'.\n"
        )
        return 2

    # Rule 3: if there's content after subject, require blank line separator
    if len(lines) > 1 and lines[1] != "":
        sys.stderr.write(
            "Missing blank line between subject and body. "
            "Format: subject line, blank line, then body.\n"
        )
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

