#!/usr/bin/env python3
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool == "Bash":
        cmd = inp.get("command", "")

        # Check if command involves git add or git commit
        if "git add" not in cmd and "git commit" not in cmd:
            return 0

        # Block explicit .env references
        if ".env" in cmd and (".env " in cmd or ".env'" in cmd or '.env"' in cmd or cmd.endswith(".env")):
            print("BLOCKED: Cannot stage/commit .env files (CLAUDE.md: 'never commit a real `.env`')", file=sys.stderr)
            return 2

        # Block broad staging patterns that would include untracked .env
        broad_patterns = ["git add .", "git add -A", "git add --all", "git commit -a", "git commit --all"]
        if any(pattern in cmd for pattern in broad_patterns):
            print("BLOCKED: Cannot use broad git staging (., -A, --all, -a) which may include .env files. Stage specific files instead.", file=sys.stderr)
            return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())
